cd /tmp/sv-e09fe42f72034de7a7da56b83ecc4048 && python3 -c "
# Check which section these addresses fall in
sections = [
    (0x0c2480, 0x0c2480 + 0x22a078, '.text'),
    (0x2ec500, 0x2ec500 + 0x003310, '.plt'),
    (0x2f3810, 0x2f3810 + 0x003208, '.data.rel.ro'),
]
for pc in [0x222098, 0x2241ac, 0x1abc80, 0x16de04, 0x2f4b20, 0x2f4c84, 0x2c1a40]:
    for start, end, name in sections:
        if start <= pc < end:
            print(f'{pc:#x} -> {name} (offset {pc - start:#x})')
            break
    else:
        print(f'{pc:#x} -> unknown section')
"

